/**
 * Monta payload OPIN-style para a seguradora de auto.
 *
 * Esquema esperado pelo mock:
 *   data: {
 *     veiculo: { placa, chassi?, marca, modelo, anoModelo, combustivel, categoria },
 *     condutor: { cpf, dataNascimento, sexo, cnhDesde, estadoCivil, usoPrincipal },
 *     localizacao: { cep, cidade, usoComercial, garagem },
 *     cobertura: { tipo, franquiaPerfil, rcfMateriais?, rcfCorporais?, appCapital? }
 *   }
 */

const input = $('Gatilho').first().json;

const obrigatorios = [
  'placa', 'ano_modelo', 'condutor_cpf', 'condutor_data_nascimento',
  'condutor_sexo', 'cep', 'tipo_cobertura'
];
for (const campo of obrigatorios) {
  if (input[campo] === undefined || input[campo] === null || input[campo] === '') {
    throw new Error(`Campo obrigatório ausente: ${campo}`);
  }
}

const dataNasc = DateTime.fromISO(input.condutor_data_nascimento);
if (!dataNasc.isValid) {
  throw new Error('condutor_data_nascimento inválida. Esperado AAAA-MM-DD.');
}

const sexoNorm = String(input.condutor_sexo).toLowerCase().charAt(0);
if (!['m', 'f'].includes(sexoNorm)) {
  throw new Error('condutor_sexo inválido. Use "m" ou "f".');
}

const anoModelo = Number(input.ano_modelo);
if (!Number.isFinite(anoModelo) || anoModelo < 1980 || anoModelo > 2100) {
  throw new Error('ano_modelo inválido.');
}

const tipoCob = String(input.tipo_cobertura).toLowerCase();
if (!['compreensiva', 'rcf', 'app', 'basica'].includes(tipoCob)) {
  throw new Error('tipo_cobertura deve ser "compreensiva", "rcf", "app" ou "basica".');
}

const idempotencyKey = input.idempotency_key || `task-${input.task_id}`;

const payload = {
  data: {
    veiculo: {
      placa: String(input.placa).toUpperCase().replace(/[^A-Z0-9]/g, ''),
      chassi: String(input.chassi ?? '').toUpperCase().replace(/[^A-Z0-9]/g, ''),
      marca: String(input.marca ?? '').toLowerCase(),
      modelo: String(input.modelo ?? '').toLowerCase(),
      anoModelo,
      combustivel: String(input.combustivel ?? 'flex').toLowerCase(),
      categoria: String(input.categoria ?? 'passeio').toLowerCase(),
    },
    condutor: {
      cpf: String(input.condutor_cpf).replace(/\D/g, ''),
      dataNascimento: String(input.condutor_data_nascimento).slice(0, 10),
      sexo: sexoNorm,
      cnhDesde: input.cnh_desde ? String(input.cnh_desde).slice(0, 10) : null,
      estadoCivil: String(input.estado_civil ?? 'solteiro').toLowerCase(),
      usoPrincipal: String(input.uso_principal ?? 'particular').toLowerCase(),
    },
    localizacao: {
      cep: String(input.cep).replace(/\D/g, ''),
      cidade: String(input.cidade ?? '').toLowerCase(),
      usoComercial: Boolean(input.uso_comercial ?? false),
      garagem: Boolean(input.garagem ?? true),
    },
    cobertura: {
      tipo: tipoCob,
      franquiaPerfil: String(input.franquia_perfil ?? 'normal').toLowerCase(),
      rcfMateriais: Number(input.rcf_materiais ?? 0) || 0,
      rcfCorporais: Number(input.rcf_corporais ?? 0) || 0,
      appCapital: Number(input.app_capital ?? 0) || 0,
    }
  }
};

return [{
  json: { payload, idempotencyKey, task_id: input.task_id, account_id: input.account_id, conversation_id: input.conversation_id, board_id: input.board_id }
}];

/**
 * Normaliza a resposta da seguradora de auto e guarda o payload original
 * para emissão stateless depois.
 */
const resposta = $input.first().json;

if (!resposta || !resposta.data) {
  throw new Error('Resposta inesperada da seguradora: ' + JSON.stringify(resposta).slice(0, 300));
}

const { consentId, planos, validadeDias } = resposta.data;

const valorEstimadoAnual = planos.length > 0
  ? Math.round(planos.reduce((sum, p) => sum + (p.premio?.anual || 0), 0) / planos.length)
  : 0;
const disclaimer = resposta.meta?.disclaimer;

const input = $('Gatilho').first().json;
const montarPayload = $('Montar payload').first().json;
const payloadOriginal = montarPayload.payload;
const idempotencyKey = montarPayload.idempotencyKey;

function formatBRL(v) { return v.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' }); }

function labelCobertura(c) {
  const map = {
    compreensiva: 'Compreensiva (casco + RCF + APP)',
    rcf: 'Responsabilidade civil facultativa',
    app: 'Acidentes pessoais de passageiros',
    basica: 'Básica',
    rcf_materiais: 'RCF danos materiais',
    rcf_corporais: 'RCF danos corporais',
    app_acidentes_pessoais: 'APP — acidentes pessoais'
  };
  const nome = map[c.tipo] ?? c.tipo;
  if (c.valorFipeSimulado !== undefined) {
    return `  · ${nome} — FIPE: ${formatBRL(c.valorFipeSimulado)} / Franquia: ${formatBRL(c.franquia)}`;
  }
  if (c.capital !== undefined) return `  · ${nome}: ${formatBRL(c.capital)}`;
  return `  · ${nome}`;
}

const resumoTexto = planos.map((p, i) => {
  const linhas = [
    `*Opção ${i + 1}: ${p.produto.nome}*`,
    `  Mensalidade: ${formatBRL(p.premio.mensal)}  ·  Anual: ${formatBRL(p.premio.anual)}`,
    `  Coberturas:`
  ];
  p.coberturas.forEach(c => linhas.push(labelCobertura(c)));
  if (p.assistencia24h?.length) linhas.push(`  Assistência 24h: ${p.assistencia24h.join(', ')}`);
  return linhas.join('\n');
}).join('\n\n');

const autoCustomFields = {
  placa: String(input.placa || '').toUpperCase().replace(/[^A-Z0-9]/g, ''),
  marca_modelo: [input.marca, input.modelo].filter(Boolean).map(s => String(s).trim()).filter(Boolean).join(' '),
  ano_modelo: input.ano_modelo != null ? String(input.ano_modelo) : '',
  chassi: String(input.chassi || '').toUpperCase().replace(/[^A-Z0-9]/g, ''),
  cep_pernoite: String(input.cep || '').replace(/\D/g, ''),
  uso_veiculo: input.uso_comercial ? 'comercial' : String(input.uso_principal || 'particular').toLowerCase(),
  perfil_condutor_principal: [
    input.condutor_sexo ? String(input.condutor_sexo).toLowerCase() : null,
    input.condutor_data_nascimento ? 'nascido em ' + String(input.condutor_data_nascimento).slice(0, 10) : null,
    input.cnh_desde ? 'CNH desde ' + String(input.cnh_desde).slice(0, 10) : null,
    input.estado_civil ? String(input.estado_civil).toLowerCase() : null
  ].filter(Boolean).join(', ')
};

return [{
  json: {
    consentId,
    validadeDias,
    planos,
    disclaimer,
    resumo_texto: resumoTexto,
    task_id: input.task_id,
    account_id: input.account_id,
    board_id: input.board_id,
    idempotency_key: idempotencyKey,
    original_quote_request: payloadOriginal.data,
    valor_estimado_anual: valorEstimadoAnual,
    auto_custom_fields: autoCustomFields
  }
}];
